SELECT version_description
FROM weather_data_versions
WHERE approval_status = 'draft';

SELECT COUNT(*) AS approved_comments_count
FROM weather_data_comments
WHERE is_approved = 1;

SELECT file_path
FROM weather_data_files
WHERE upload_date = '2023-01-02';

SELECT flag_type, flag_description
FROM weather_data_flags
WHERE priority = 'high' AND resolution_date IS NULL;

SELECT flag_type, GROUP_CONCAT(priority) AS priorities
FROM weather_data_flags
GROUP BY flag_type;

SELECT COUNT(DISTINCT user_id) AS unique_users
FROM access_logs
WHERE access_date >= DATE('now', '-30 days');

SELECT metadata_value
FROM weather_data_metadata
WHERE metadata_key = 'collection_method';

SELECT file_format, SUM(file_size) AS total_size_mb
   FROM weather_data_files
   GROUP BY file_format;

SELECT file_path, file_size
FROM weather_data_files
ORDER BY file_size DESC;

SELECT comment_text
FROM weather_data_comments
WHERE is_approved = 1;
